CREATE OR REPLACE FUNCTION OFSERM.ABL_BANKING_CARDS_EXPOSURE_DATA_CREATION(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_BANKING_EXPOSURES(N_COUNTRY_SKEY,N_CREDIT_STATUS_SKEY,N_MIS_DATE_SKEY,N_ACCT_SKEY,N_GAAP_SKEY,N_ISSUE_SKEY,F_FINANCIAL_ENTITY_IND,F_REGULATED_FIN_ENTITY_IND,N_CUST_SKEY,N_COUNTERPARTY_TYPE_SKEY,F_EXP_REV_FLAG,F_INTERNAL_CUST_IND,F_PREF_TREATMENT_FLAG,F_RW_BY_DISCRETION,N_COVERED_RWA_UL,N_CURR_12M_ECL,N_EL_AMOUNT,N_EXPOSURE_AMOUNT,N_EXP_COVERED_AMT,N_EXP_UNCOVERED_AMT,N_GROUP_ASSET_SIZE,N_LOSS_ALLOWANCE_LIFE_ECL,N_ORIGINAL_MATURITY,N_PARENT_ACCT_SKEY,N_PRE_MITIGATION_RWA_EL,N_RESIDUAL_MATURITY,N_RUN_PARAMETER_SETUP_SKEY,N_RUN_SKEY,N_RWA_EL_AMT,N_RWA_UL_AMT,N_CUST_ANNUAL_SALES,N_SHAREHOLDING_PERCENT,N_UNCOVERED_RWA_UL,N_UNDRAWN_AMOUNT,V_APPROACH_TYPE,V_EXP_RCY_CODE,N_ENTITY_SKEY,F_CASH_POOL_DAILY_TRANSFER,F_CASH_POOL_LEGAL_ENFORCEABLE,F_CREDIT_IMPAIRMENT_FLAG,F_FINANCIAL_ASSET_IFRS9_FLAG,N_CCF_OWN_ESTIMATE,N_EFF_MATURITY,N_EL_BEST_ESTIMATE_PERCENT,N_LGD_PERCENT_PRE_CRM,N_LONG_RUN_WEIGHTED_AVG_LGD,N_PD_PERCENT,N_PROVISION_AMOUNT,N_CAP_APPROACH_TYPE_SKEY,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE,N_BASEL_PARTY_GRADE_SKEY,N_STD_COUNTERPARTY_TYPE_SKEY,N_BASEL_TXN_TYPE_SKEY,N_BASEL_PROD_TYPE_SKEY,N_STD_SENIORITY_SKEY,N_SEC_POOL_SKEY,D_EXPOSURE_END_DATE,D_EXPOSURE_START_DATE,F_AUTO_CANCELLATION_FLAG,F_EXP_DEFAULTED_FLAG,F_EXP_FUND_CCY_SAME_IND,F_PAST_DUE_FLAG,F_SECURED_IND,F_SECURITIZED_FLAG,F_UNCOND_CANCELLED_EXP_IND,N_DELQ_DAYS,N_EXP_LTV_RATIO,N_LOAD_RUN_ID,V_CCY_CODE,V_PRODUCT_BOOK_CODE)SELECT  /*+PARALLEL (4)*/ to_char(DIM_COUNTRY.N_COUNTRY_SKEY),to_char(DIM_CREDIT_STATUS.N_CREDIT_STATUS_SKEY),to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_EXPOSURE.N_ACCT_SKEY),to_char(DIM_GAAP.N_GAAP_SKEY),to_char(DIM_ISSUE.N_ISSUE_SKEY),DIM_PARTY.F_FINANCIAL_ENTITY_IND,DIM_PARTY.F_REGULATED_FIN_ENTITY_IND,to_char(DIM_PARTY.N_PARTY_SKEY),to_char(DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY),'Y',CASE WHEN COALESCE(INTERNAL_ENTITY.N_ENTITY_SKEY,-99999)=-99999   AND DIM_BASEL_CAP_CONSL_APPR_CUST.v_basel_cap_consl_appr_code IN ('FLCS', 'PRCS','FAGR','PRAGR') THEN 'Y' ELSE 'N' END,'N','N',0,CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_STD END,0,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE*(CASE WHEN STG_CARDS.N_EOP_BAL > 0 THEN STG_CARDS.N_EOP_BAL ELSE 0 END),0,0,FSI_CAP_PARTY_FINANCIALS.N_GROUP_ASSET_SIZE * B_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_STD END,DAYS_BETWEEN(STG_CARDS.D_ACCT_OPEN_DATE,STG_CARDS.D_ACCT_MATURITY_DATE,STG_CARDS.V_DAY_COUNT_IND),DIM_PARENT_EXPOSURE.N_ACCT_SKEY,0,DAYS_BETWEEN(STG_CARDS.FIC_MIS_DATE,STG_CARDS.D_ACCT_MATURITY_DATE,STG_CARDS.V_DAY_COUNT_IND),CASE WHEN FSI_CAP_RUN_EXE_PARAMETERS.F_PORTFOLIO_BASED_FLAG ='N' THEN RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY ELSE NULL END,'870',0,0,FSI_CAP_PARTY_FINANCIALS.N_SALES_AMT* A_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN DIM_BASEL_CAP_CONSL_APPR.v_basel_cap_consl_appr_code = 'PRCS' THEN FCT_ENTITY_INFO.n_shareholding_percent ELSE 1 END,0,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE*STG_CARDS.N_UNDRAWN_AMOUNT,CASE WHEN FSI_CAP_RUN_EXE_PARAMETERS.F_PORTFOLIO_BASED_FLAG ='N' THEN FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE ELSE NULL END,RUN_EXE_PARAMETERS_RCY.V_PARAM_VALUE_CODE,to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),FSI_ACCT_MODELING_INFO.F_CASH_POOL_DAILY_TRANSFER,FSI_ACCT_MODELING_INFO.F_CASH_POOL_LEGAL_ENFORCEABLE,FSI_ACCT_MODELING_INFO.F_CREDIT_IMPAIRMENT_FLAG,FSI_ACCT_MODELING_INFO.F_FINANCIAL_ASSET_IFRS9_FLAG,to_char(FSI_ACCT_MODELING_INFO.N_CCF_OWN_ESTIMATE),to_char(FSI_ACCT_MODELING_INFO.N_EFF_MATURITY),to_char(FSI_ACCT_MODELING_INFO.N_EL_BEST_ESTIMATE_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LONG_RUN_WEIGHTED_AVG_LGD),to_char(FSI_ACCT_MODELING_INFO.N_PD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_PROVISION_AMOUNT),to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(FSI_PARTY_GRADE_RECLASS.N_BASEL_GRADE_SKEY),to_char(FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY),to_char(FSI_PROD_TXN_TYPE_RECLASS.N_BASEL_TXN_TYPE_SKEY),to_char(FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY),to_char(FSI_SENIORITY_RECLASSIFICATION.N_STD_SENIORITY_SKEY),to_char(SEC_POOL_MASTER.N_SEC_POOL_SKEY),STG_CARDS.D_ACCT_MATURITY_DATE,STG_CARDS.D_ACCT_OPEN_DATE,STG_CARDS.F_AUTO_CANCELLATION_FLAG,STG_CARDS.F_EXP_DEFAULTED_FLAG,STG_CARDS.F_EXP_FUND_CCY_SAME_IND,STG_CARDS.F_PAST_DUE_FLAG,STG_CARDS.F_SECURED_IND,STG_CARDS.F_SECURITIZED_FLAG,STG_CARDS.F_UNCOND_CANCELLED_EXP_IND,to_char(STG_CARDS.N_ACCT_DELQ_DAYS),to_char(STG_CARDS.N_EXP_LTV_RATIO),to_char(STG_CARDS.N_LOAD_RUN_ID),STG_CARDS.V_CCY_CODE,STG_CARDS.V_PRODUCT_BOOK_CODE FROM stg_cards INNER JOIN DIM_DATES ON STG_CARDS.fic_mis_date = DIM_DATES.D_CALENDAR_DATE AND dim_dates.d_calendar_date = to_date('20260331','YYYYMMDD') INNER JOIN dim_run ON dim_run.n_run_skey = '870' INNER JOIN dim_exposure ON stg_cards.v_account_number = dim_exposure.v_exposure_id AND to_date('20260331','YYYYMMDD') BETWEEN dim_exposure.d_record_start_date AND dim_exposure.d_record_end_date LEFT OUTER JOIN dim_exposure dim_parent_exposure ON stg_cards.v_parent_exposure_id = dim_parent_exposure.v_exposure_id AND to_date('20260331','YYYYMMDD') BETWEEN dim_parent_exposure.d_record_start_date AND dim_parent_exposure.d_record_end_date LEFT OUTER JOIN dim_lob ON stg_cards.v_lob_code = dim_lob.v_lob_code AND to_date('20260331','YYYYMMDD') BETWEEN dim_lob.d_record_start_date AND dim_lob.d_record_end_date INNER JOIN dim_gaap ON stg_cards.v_gaap_code = dim_gaap.v_gaap_code AND to_date('20260331','YYYYMMDD') BETWEEN dim_gaap.d_record_start_date AND dim_gaap.d_record_end_date LEFT OUTER JOIN dim_product ON stg_cards.v_prod_code = dim_product.v_prod_code AND to_date('20260331','YYYYMMDD') BETWEEN dim_product.d_record_start_date AND dim_product.d_record_end_date LEFT OUTER JOIN dim_party ON coalesce(stg_cards.v_cust_ref_code, 'MSG') = dim_party.v_party_id AND to_date('20260331','YYYYMMDD') BETWEEN dim_party.d_record_start_date AND dim_party.d_record_end_date INNER JOIN dim_party_type ON coalesce(dim_party.v_party_type, 'MSG') = coalesce(dim_party_type.v_party_type_code, 'MSG') AND to_date('20260331','YYYYMMDD') BETWEEN dim_party_type.d_record_start_date AND dim_party_type.d_record_end_date LEFT OUTER JOIN sec_pool_master ON stg_cards.v_sec_pool_id = sec_pool_master.v_sec_pool_id AND to_date('20260331','YYYYMMDD') BETWEEN sec_pool_master.d_record_start_date AND sec_pool_master.d_record_end_date LEFT OUTER JOIN dim_geography ON coalesce(dim_party.v_branch_code, 'MSG') = dim_geography.v_acct_branch_code AND to_date('20260331','YYYYMMDD') BETWEEN dim_geography.d_record_start_date AND dim_geography.d_record_end_date LEFT OUTER JOIN dim_industry ON dim_industry.v_d_cust_industry = coalesce(dim_party.v_industry_code, 'MSG') AND to_date('20260331','YYYYMMDD') BETWEEN dim_industry.d_record_start_date AND dim_industry.d_record_end_date /*LEFT OUTER JOIN DIM_PARTY_TYPE ON STG_CARDS.V_CUST_TYPE = DIM_PARTY_TYPE.v_party_type_code*/ INNER JOIN FCT_ENTITY_INFO ON FCT_ENTITY_INFO.N_RUN_SKEY = '870' AND STG_CARDS.V_LV_CODE = FCT_ENTITY_INFO.V_ENTITY_CODE INNER JOIN DIM_BASEL_CAP_CONSL_APPR ON DIM_BASEL_CAP_CONSL_APPR.N_BASEL_CAP_CONSL_APPR_SKEY = FCT_ENTITY_INFO.N_BASEL_CAP_CONSL_APPR_SKEY LEFT OUTER JOIN FCT_ENTITY_INFO INTERNAL_ENTITY ON INTERNAL_ENTITY.N_RUN_SKEY = '870' AND INTERNAL_ENTITY.N_MIS_DATE_SKEY = TO_NUMBER(TO_CHAR(to_date('20260331','YYYYMMDD'), 'YYYYMMDD')) AND INTERNAL_ENTITY.V_PARTY_ID = DIM_PARTY.v_party_id AND INTERNAL_ENTITY.F_CAP_CONSL_ENTITY_IND = 'Y' LEFT OUTER JOIN DIM_BASEL_CAP_CONSL_APPR DIM_BASEL_CAP_CONSL_APPR_CUST ON DIM_BASEL_CAP_CONSL_APPR_CUST.N_BASEL_CAP_CONSL_APPR_SKEY = INTERNAL_ENTITY.N_BASEL_CAP_CONSL_APPR_SKEY AND DIM_BASEL_CAP_CONSL_APPR_CUST.V_BASEL_CAP_CONSL_APPR_CODE IN ( 'FLCS' ,'PRCS' ,'FAGR' ,'PRAGR' ) AND internal_entity.f_cap_consl_entity_ind = 'Y' LEFT OUTER JOIN dim_issue ON stg_cards.v_account_number = dim_issue.v_issue_code AND stg_cards.fic_mis_date BETWEEN dim_issue.d_record_start_date AND dim_issue.d_record_end_date LEFT OUTER JOIN fsi_cap_party_financials ON fsi_cap_party_financials.n_run_skey = dim_run.n_run_skey AND fsi_cap_party_financials.n_mis_date_skey = dim_dates.n_date_skey AND fsi_cap_party_financials.n_party_skey = dim_party.n_party_skey LEFT OUTER JOIN RUN_EXE_PARAMETERS ON RUN_EXE_PARAMETERS.N_RUN_SKEY = '870' AND RUN_EXE_PARAMETERS.V_PARAM_ID = 'LE' LEFT OUTER JOIN DIM_ORG_STRUCTURE ON DIM_ORG_STRUCTURE.V_ENTITY_CODE = RUN_EXE_PARAMETERS.V_PARAM_VALUE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ORG_STRUCTURE.D_RECORD_START_DATE AND DIM_ORG_STRUCTURE.D_RECORD_END_DATE LEFT OUTER JOIN run_exe_parameters run_exe_parameters_rcy ON run_exe_parameters_rcy.n_run_skey = dim_run.n_run_skey AND run_exe_parameters_rcy.v_param_id = 'RCY' LEFT OUTER JOIN dim_credit_status ON stg_cards.v_credit_status_cd = dim_credit_status.v_credit_status AND stg_cards.fic_mis_date BETWEEN dim_credit_status.d_record_start_date AND dim_credit_status.d_record_end_date LEFT OUTER JOIN dim_location ON dim_location.v_location_code = dim_party.v_location_code AND stg_cards.fic_mis_date BETWEEN dim_location.d_record_start_date AND dim_location.d_record_end_date LEFT OUTER JOIN fsi_reg_prod_type_reclass ON fsi_reg_prod_type_reclass.n_mis_date_skey = dim_dates.n_date_skey AND fsi_reg_prod_type_reclass.n_run_skey = '870' AND fsi_reg_prod_type_reclass.n_prod_skey = dim_product.n_prod_skey LEFT OUTER JOIN dim_basel_product_type ON dim_basel_product_type.n_basel_prod_type_skey = fsi_reg_prod_type_reclass.n_basel_prod_type_skey LEFT OUTER JOIN fsi_party_type_classification ON fsi_party_type_classification.n_mis_date_skey = dim_dates.n_date_skey AND fsi_party_type_classification.n_run_skey = '870' AND fsi_party_type_classification.n_party_type_skey = dim_party_type.n_party_type_skey LEFT OUTER JOIN dim_business_unit ON stg_cards.v_business_unit_code = dim_business_unit.v_business_unit_code LEFT OUTER JOIN dim_credit_line ON stg_cards.v_guarantor_line_code = dim_credit_line.v_credit_line_code AND stg_cards.fic_mis_date BETWEEN dim_credit_line.d_record_start_date AND dim_credit_line.d_record_end_date LEFT OUTER JOIN fsi_cap_currency_conversion ON fsi_cap_currency_conversion.n_mis_date_skey = dim_dates.n_date_skey AND dim_run.n_run_skey = fsi_cap_currency_conversion.n_run_skey AND fsi_cap_currency_conversion.v_ccy_code = stg_cards.v_ccy_code LEFT OUTER JOIN fsi_cap_currency_conversion a_fsi_cap_currency_conversion ON a_fsi_cap_currency_conversion.n_mis_date_skey = dim_dates.n_date_skey AND dim_run.n_run_skey = a_fsi_cap_currency_conversion.n_run_skey AND a_fsi_cap_currency_conversion.v_ccy_code = fsi_cap_party_financials.v_ccy_code LEFT OUTER JOIN fsi_cap_currency_conversion b_fsi_cap_currency_conversion ON b_fsi_cap_currency_conversion.n_mis_date_skey = dim_dates.n_date_skey AND dim_run.n_run_skey = b_fsi_cap_currency_conversion.n_run_skey AND b_fsi_cap_currency_conversion.v_ccy_code = fsi_cap_party_financials.v_group_ccy_code  LEFT OUTER JOIN fsi_prod_txn_type_reclass ON fsi_prod_txn_type_reclass.n_basel_prod_type_skey = dim_basel_product_type.n_basel_prod_type_skey AND fsi_prod_txn_type_reclass.n_run_skey = '870' AND fsi_prod_txn_type_reclass.n_mis_date_skey = dim_dates.n_date_skey LEFT OUTER JOIN fsi_acct_modeling_info ON fsi_acct_modeling_info.v_exposure_id = dim_exposure.v_exposure_id AND stg_cards.fic_mis_date BETWEEN fsi_acct_modeling_info.d_record_start_date AND fsi_acct_modeling_info.d_record_end_date LEFT OUTER JOIN fsi_cap_run_exe_parameters ON dim_run.n_run_skey = fsi_cap_run_exe_parameters.n_run_skey AND dim_dates.n_date_skey = fsi_cap_run_exe_parameters.n_mis_date_skey LEFT OUTER JOIN fsi_basel_exec_appr_details ON fsi_basel_exec_appr_details.n_mis_date_skey = dim_dates.n_date_skey AND fsi_basel_exec_appr_details.n_run_skey = dim_run.n_run_skey AND fsi_basel_exec_appr_details.v_risk_sub_type = 'NONSEC' AND fsi_cap_run_exe_parameters.f_portfolio_based_flag = 'N' LEFT OUTER JOIN run_parameters ON run_parameters.n_mis_date_skey = dim_dates.n_date_skey AND run_parameters.n_run_skey = dim_run.n_run_skey AND fsi_basel_exec_appr_details.n_run_parameter_skey = run_parameters.n_run_parameter_skey LEFT OUTER JOIN dim_country ON stg_cards.v_country_id = dim_country.v_country_id AND stg_cards.fic_mis_date BETWEEN dim_country.d_record_start_date AND dim_country.d_record_end_date LEFT OUTER JOIN fsi_cap_approach_type_master ON fsi_cap_approach_type_master.v_approach_type = fsi_basel_exec_appr_details.v_approach_type_code LEFT OUTER JOIN fsi_cap_record_type_master ON fsi_cap_record_type_master.v_record_type = 'BNK_NON_SEC_EXP' LEFT OUTER JOIN fsi_party_grade_reclass ON fsi_party_grade_reclass.n_party_skey = dim_party.n_party_skey AND fsi_party_grade_reclass.n_run_skey = dim_run.n_run_skey AND fsi_party_grade_reclass.n_mis_date_skey = dim_dates.n_date_skey AND fsi_party_grade_reclass.n_standard_party_type_skey = fsi_party_type_classification.n_standard_party_type_skey LEFT JOIN DIM_EXPOSURE_SENIORITY ON DIM_EXPOSURE_SENIORITY.V_SENIORITY_CODE = stg_cards.V_SENIORITY_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_EXPOSURE_SENIORITY.D_RECORD_START_DATE AND DIM_EXPOSURE_SENIORITY.D_RECORD_END_DATE LEFT JOIN FSI_SENIORITY_RECLASSIFICATION ON FSI_SENIORITY_RECLASSIFICATION.N_SENIORITY = DIM_EXPOSURE_SENIORITY.N_EXP_SENIORITY  AND FSI_SENIORITY_RECLASSIFICATION.N_RUN_SKEY = '870' AND FSI_SENIORITY_RECLASSIFICATION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY WHERE 1=1 AND COALESCE(FCT_ENTITY_INFO.F_CAP_CONSL_ENTITY_IND, 'N') = 'Y' AND DIM_BASEL_CAP_CONSL_APPR.V_BASEL_CAP_CONSL_APPR_CODE IN ( 'FLCS' ,'PRCS' ) AND COALESCE(STG_CARDS.F_SECURITIZED_FLAG, 'N') <> 'Y' AND COALESCE(STG_CARDS.D_ACCT_CLOSED_DATE, STG_CARDS.FIC_MIS_DATE) >= STG_CARDS.FIC_MIS_DATE AND STG_CARDS.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') AND EXISTS ( SELECT 1 FROM FSI_CAP_ACCOUNT_LOAD_RUN_MAP WHERE FSI_CAP_ACCOUNT_LOAD_RUN_MAP.V_ACCOUNT_NUMBER  = DIM_EXPOSURE.V_EXPOSURE_ID AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.FIC_MIS_DATE = DIM_DATES.D_CALENDAR_DATE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.V_GAAP_CODE = DIM_GAAP.V_GAAP_CODE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_RUN_SKEY = '870' AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_LOAD_RUN_ID = STG_CARDS.N_LOAD_RUN_ID) AND STG_CARDS.V_DATA_JURISDICTION='BASEL' LOG ERRORS INTO FSI_CAP_BANKING_EXPOSURES$ ('1776768366715_76714877_20260331_1_Job_37a0849cf9bc48a286d45def6ecf2e5c') REJECT LIMIT UNLIMITED;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
